33	// NewExternalBackend creates a backend that shells out to the given tool.
34	func NewExternalBackend(tool, collection string) (*ExternalBackend, error) {
35		if _, err := exec.LookPath(tool); err != nil {
36			return nil, fmt.Errorf("bead: backend %s not found in PATH", tool)
37		}
38		return &ExternalBackend{Tool: tool, Collection: collection}, nil
39	}
