144	// Init creates the storage directory and file.
145	func (s *Store) Init() error {
146		if s.backend != nil {
147			return s.backend.Init()
148		}
149		if err := os.MkdirAll(s.Dir, 0o755); err != nil {
150			return fmt.Errorf("bead: init dir: %w", err)
151		}
152		f, err := os.OpenFile(s.File, os.O_CREATE|os.O_WRONLY, 0o644)
153		if err != nil {
154			return fmt.Errorf("bead: init file: %w", err)
155		}
156		return f.Close()
157	}
