173	// ReadAllFiltered loads all beads, folds them by latest-wins, and returns only
174	// those for which the predicate returns true. When the predicate is nil every
175	// bead is returned (equivalent to ReadAll). The predicate is applied at the
176	// per-entry parse boundary after fold — matched beads are appended directly to
177	// the return slice without first being held in an intermediate full-corpus
178	// list, so queries that match a small subset avoid materializing the
179	// mismatches (ddx-9ce6842a Part 2 step 2: filter pushdown).
180	func (s *Store) ReadAllFiltered(pred func(Bead) bool) ([]Bead, error) {
181		if s.backend != nil {
182			all, err := s.backend.ReadAll()
183			if err != nil {
184				return nil, err
185			}
186			if pred == nil {
187				return all, nil
188			}
189			out := make([]Bead, 0, len(all))
190			for _, b := range all {
191				if pred(b) {
192					out = append(out, b)
193				}
194			}
195			return out, nil
196		}
197		beads, warnings, err := s.readAllRaw()
198		if err != nil {
199			return nil, fmt.Errorf("bead: read %s: %w", s.File, err)
200		}
201		beads = foldLatestBeads(beads)
202		for _, warning := range warnings {
203			fmt.Fprintln(os.Stderr, warning)
204		}
205		if len(warnings) > 0 && len(beads) > 0 {
206			repaired, repairErr := s.repairJSONL()
207			if repairErr != nil {
208				return beads, fmt.Errorf("bead: repair %s: %w", s.File, repairErr)
209			}
210			if repaired {
211				fmt.Fprintf(os.Stderr, "bead: repaired %s; backup written to %s.bak\n", s.File, s.File)
212			}
213		}
214		if len(beads) == 0 && len(warnings) > 0 {
215			return nil, fmt.Errorf("bead: read %s: %d malformed record(s), 0 valid", s.File, len(warnings))
216		}
217		if pred == nil {
218			return beads, nil
219		}
220		out := make([]Bead, 0, len(beads))
221		for _, b := range beads {
222			if pred(b) {
223				out = append(out, b)
224			}
225		}
226		return out, nil
227	}
