229	func (s *Store) readAllRaw() ([]Bead, []string, error) {
230		data, err := os.ReadFile(s.File)
231		if os.IsNotExist(err) {
232			return nil, nil, nil
233		}
234		if err != nil {
235			return nil, nil, fmt.Errorf("read: %w", err)
236		}
237		beads, warnings, err := parseBeadJSONL(data)
238		if err != nil {
239			return nil, nil, err
240		}
241		return beads, warnings, nil
242	}
