244	func parseBeadJSONL(data []byte) ([]Bead, []string, error) {
245		scanner := bufio.NewScanner(bytes.NewReader(data))
246		// 16MB max line. Real-world extremes observed: 1.46MB bead rows when a
247		// reviewer stream dumped into events[].body, and bd-exported lines stacking
248		// many 65KB fields. bd's upstream per-field cap is 65,535 bytes; an
249		// individual bead with dozens of maxed-out fields fits comfortably in 16MB.
250		scanner.Buffer(make([]byte, 0, 64*1024), 16*1024*1024)
251	
252		var beads []Bead
253		var warnings []string
254		lineNo := 0
255		for scanner.Scan() {
256			lineNo++
257			line := strings.TrimSpace(scanner.Text())
258			if line == "" {
259				continue
260			}
261			b, err := unmarshalBead([]byte(line))
262			if err != nil {
263				warnings = append(warnings, fmt.Sprintf("bead: read line %d: %v", lineNo, err))
264				continue
265			}
266			beads = append(beads, b)
267		}
268		if err := scanner.Err(); err != nil {
269			return nil, nil, fmt.Errorf("scan jsonl: %w", err)
270		}
271		return beads, warnings, nil
272	}
